before_code:
library ieee;
use ieee.std_logic_1164.all;

entity decoder_4to16 is
  port (
    input_sel : in std_logic_vector(3 downto 0);
    enable : in std_logic;
    output_lines : out std_logic_vector(15 downto 0)
  );
end entity;

architecture rtl of decoder_4to16 is
begin
  process(input_sel)
  begin
    if enable = '1' then
      case input_sel is
        when "0000" => output_lines <= "0000000000000001";
        when "0001" => output_lines <= "0000000000000010";
        when "0010" => output_lines <= "0000000000000100";
        when "0011" => output_lines <= "0000000000001000";
        when others => output_lines <= (others => '0');
      end case;
    else
      output_lines <= (others => '0');
    end if;
  end process;
end architecture;

